/**
 * Validates projection specification
 */
function validateProjection(projection, collection) {
  if (projection === null || projection === undefined) {
    // Default: exclude forbidden fields
    const defaultProjection = Object.create(null);
    for (const field of FORBIDDEN_PROJECTION_FIELDS) {
      defaultProjection[field] = 0;
    }
    return defaultProjection;
  }

  if (typeof projection !== 'object' || Array.isArray(projection)) {
    throw new QueryValidationError('Projection must be a plain object', 'projection');
  }

  const sanitized = Object.create(null);
  let hasInclusion = false;
  let hasExclusion = false;

  for (const key of Object.keys(projection)) {
    if (!isSafeFieldName(key)) {
      throw new QueryValidationError(`Unsafe field name in projection: "${key}"`, key);
    }

    const value = projection[key];

    // Only allow 0 or 1 (or true/false) as projection values
    if (value !== 0 && value !== 1 && value !== true && value !== false) {
      throw new QueryValidationError(
        `Projection value for "${key}" must be 0, 1, true, or false`,
        key
      );
    }

    const numValue = value ? 1 : 0;

    // Check for forbidden fields being included
    if (FORBIDDEN_PROJECTION_FIELDS.includes(key)) {
      if (numValue === 1) {
        throw new QueryValidationError(
          `Field "${key}" cannot be included in projection (sensitive field)`,
          key
        );
      }
      // Allow explicit exclusion of forbidden fields
      sanitized[key] = 0;
      continue;
    }

    // _id can be excluded alongside inclusions
    if (key === '_id') {
      sanitized[key] = numValue;
      continue;
    }

    // Validate field is in the allowlist
    validateFieldName(key, collection, 'projection');

    if (numValue === 1) hasInclusion = true;
    if (numValue === 0) hasExclusion = true;

    sanitized[key] = numValue;
  }

  // MongoDB doesn't allow mixing inclusion and exclusion (except _id)
  if (hasInclusion && hasExclusion) {
    throw new QueryValidationError(
      'Projection cannot mix inclusion and exclusion (except for _id)',
      'projection'
    );
  }

  // Always ensure forbidden fields are excluded
  if (hasInclusion) {
    // In inclusion mode, forbidden fields are automatically excluded
    // unless explicitly included (which we already blocked above)
  } else {
    // In exclusion mode, ensure forbidden fields are excluded
    for (const field of FORBIDDEN_PROJECTION_FIELDS) {
      sanitized[field] = 0;
    }
  }

  return sanitized;
}

/**
 * Validates sort criteria
 */
function validateSort(sort, collection) {
  if (sort === null || sort === undefined) {
    return undefined;
  }

  if (typeof sort !== 'object' || Array.isArray(sort)) {
    throw new QueryValidationError('Sort must be a plain object', 'sort');
  }

  const sanitized = Object.create(null);

  for (const key of Object.keys(sort)) {
    if (!isSafeFieldName(key)) {
      throw new QueryValidationError(`Unsafe field name in sort: "${key}"`, key);
    }

    validateFieldName(key, collection, 'sort');

    const value = sort[key];
    if (value !== 1 && value !== -1) {
      throw new QueryValidationError(
        `Sort value for "${key}" must be 1 (ascending) or -1 (descending)`,
        key
      );
    }

    sanitized[key] = value;
  }

  // Limit number of sort fields
  if (Object.keys(sanitized).length > 5) {
    throw new QueryValidationError('Sort cannot have more than 5 fields', 'sort');
  }

  return sanitized;
}

/**
 * Validates pagination parameters
 */
function validatePagination(limit, skip) {
  const validatedLimit = Math.min(
    Math.max(1, parseInt(limit, 10) || DEFAULT_LIMIT),
    MAX_LIMIT
  );

  const validatedSkip = Math.min(
    Math.max(0, parseInt(skip, 10) || 0),
    MAX_SKIP
  );

  return { limit: validatedLimit, skip: validatedSkip };
}

