/**
 * Builds a safe, validated MongoDB query from dynamic input.
 *
 * @param {string} collection - The collection name (must be in allowlists)
 * @param {object} filter - Dynamic filter object with MongoDB operators
 * @param {object} projection - Field inclusion/exclusion specification
 * @param {object} sort - Sort criteria
 * @param {object} pagination - { limit, skip }
 * @returns {object} - { filter, projection, sort, limit, skip }
 */
function queryBuilder(collection, filter, projection, sort, pagination = {}) {
  // Validate collection name
  if (!ALLOWED_FIELDS[collection]) {
    throw new QueryValidationError(
      `Unknown collection: "${collection}". Allowed: ${Object.keys(ALLOWED_FIELDS).join(', ')}`,
      'collection'
    );
  }

  // Deep-clone inputs to prevent mutation of originals and prototype pollution
  const safeFilter = JSON.parse(JSON.stringify(filter || {}));
  const safeProjection = projection ? JSON.parse(JSON.stringify(projection)) : null;
  const safeSort = sort ? JSON.parse(JSON.stringify(sort)) : null;

  // Validate each component
  const validatedFilter = validateFilterObject(safeFilter, collection);
  const validatedProjection = validateProjection(safeProjection, collection);
  const validatedSort = validateSort(safeSort, collection);
  const { limit, skip } = validatePagination(pagination.limit, pagination.skip);

  return {
    filter: validatedFilter,
    projection: validatedProjection,
    sort: validatedSort,
    limit,
    skip,
  };
}

