let db;

async function connectToMongo() {
  const uri = process.env.MONGODB_URI || 'mongodb://localhost:27017';
  const client = new MongoClient(uri);
  await client.connect();
  db = client.db(process.env.DB_NAME || 'admin_dashboard');
  console.log('Connected to MongoDB');
  return client;
}

/**
 * POST /api/query/:collection
 *
 * Body:
 * {
 *   filter: { age: { $gt: 18 }, name: { $regex: "^J", $options: "i" } },
 *   projection: { password: 0 },
 *   sort: { createdAt: -1 },
 *   limit: 50,
 *   skip: 0
 * }
 */
app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter, projection, sort, limit, skip } = req.body;

    // Build and validate the query
    const query = queryBuilder(collection, filter, projection, sort, { limit, skip });

    console.log('Executing validated query:', JSON.stringify(query, null, 2));

    // Execute the query
    const results = await db
      .collection(collection)
      .find(query.filter)
      .project(query.projection)
      .sort(query.sort || {})
      .skip(query.skip)
      .limit(query.limit)
      .toArray();

    // Get total count for pagination
    const totalCount = await db
      .collection(collection)
      .countDocuments(query.filter);

    res.json({
      success: true,
      data: results,
      pagination: {
        total: totalCount,
        limit: query.limit,
        skip: query.skip,
        hasMore: query.skip + query.limit < totalCount,
      },
    });
  } catch (error) {
    if (error instanceof QueryValidationError) {
      return res.status(error.statusCode).json({
        success: false,
        error: 'Query Validation Error',
        message: error.message,
        field: error.field,
      });
    }

    console.error('Query execution error:', error);
    res.status(500).json({
      success: false,
      error: 'Internal Server Error',
      message: 'An error occurred while executing the query',
    });
  }
});

/**
 * GET /api/query/:collection/count
 * Body: { filter: { ... } }
 */
app.post('/api/query/:collection/count', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter } = req.body;

    const query = queryBuilder(collection, filter, null, null, {});

    const count = await db
      .collection(collection)
      .countDocuments(query.filter);

    res.json({
      success: true,
      count,
    });
  } catch (error) {
    if (error instanceof QueryValidationError) {
      return res.status(error.statusCode).json({
        success: false,
        error: 'Query Validation Error',
        message: error.message,
        field: error.field,
      });
    }

    console.error('Count query error:', error);
    res.status(500).json({
      success: false,
      error: 'Internal Server Error',
    });
  }
});

/**
 * GET /api/schema/:collection
 * Returns the allowed fields, operators, and constraints for a collection
 */
app.get('/api/schema/:collection', (req, res) => {
  const { collection } = req.params;

  if (!ALLOWED_FIELDS[collection]) {
    return res.status(404).json({
      success: false,
      error: `Unknown collection: "${collection}"`,
    });
  }

  res.json({
    success: true,
    schema: {
      collection,
      filterFields: ALLOWED_FIELDS[collection],
      projectionFields: ALLOWED_PROJECTION_FIELDS[collection],
      sortFields: ALLOWED_SORT_FIELDS[collection],
      allowedOperators: [...ALLOWED_OPERATORS],
      blockedOperators: [...BLOCKED_OPERATORS],
      constraints: {
        maxQueryDepth: MAX_QUERY_DEPTH,
        maxArrayLength: MAX_ARRAY_LENGTH,
        maxStringLength: MAX_STRING_LENGTH,
        maxRegexLength: MAX_REGEX_LENGTH,
        maxLimit: MAX_LIMIT,
        defaultLimit: DEFAULT_LIMIT,
        maxSkip: MAX_SKIP,
      },
    },
  });
});

